import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Creating a buffer with a dynamic size based on user input length
        char[] buffer = new char[Math.min(name.length(), 10)];

        // Copying the user input into the dynamically sized buffer
        for (int i = 0; i < buffer.length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

